Here's a C++ function that converts a `std::string` containing **Markdown** text into **HTML** formatted text. This is a **basic implementation** that handles a few common Markdown elements like:

- **Bold** (`**text**` → `<strong>text</strong>`)
- *Italic* (`*text*` → `<em>text</em>`)
- Headings (`# Heading` → `<h1>Heading</h1>`)
- Unordered lists (`- item` → `<ul><li>item</li></ul>`)
- Ordered lists (`1. item` → `<ol><li>item</li></ol>`)

> **Note:** This is a simplified version and does **not** handle all Markdown syntax or edge cases. For a full Markdown parser, consider using a library like [markdown.cpp](https://github.com/jbeder/markdown) or [pugixml](https://github.com/zeux/pugixml).

---

### ✅ C++ Function: Markdown to HTML

```cpp
#include <string>
#include <sstream>
#include <vector>
#include <algorithm>

std::string markdownToHtml(const std::string& markdown) {
    std::string html;
    std::istringstream iss(markdown);
    std::string line;
    bool inList = false;
    int listLevel = 0;

    while (std::getline(iss, line)) {
        // Trim leading and trailing whitespace
        line.erase(0, line.find_first_not_of(" \t"));
        line.erase(line.find_last_not_of(" \t") + 1);

        // Handle headings
        if (line.substr(0, 1) == "#") {
            int level = 1;
            while (line[0] == '#') {
                line.erase(0, 1);
                level++;
            }
            html += "<h" + std::to_string(level) + ">" + line + "</h" + std::to_string(level) + ">\n";
            continue;
        }

        // Handle bold and italic
        std::string processedLine = line;
        size_t pos = 0;

        // Replace **text** with <strong>text</strong>
        while ((pos = processedLine.find("**", pos)) != std::string::npos) {
            size_t end = processedLine.find("**", pos + 2);
            if (end != std::string::npos) {
                std::string text = processedLine.substr(pos + 2, end - pos - 2);
                processedLine.replace(pos, end - pos, "<strong>" + text + "</strong>");
                pos += 14; // length of "<strong>text</strong>"
            } else {
                break;
            }
        }

        // Replace *text* with <em>text</em>
        pos = 0;
        while ((pos = processedLine.find("*", pos)) != std::string::npos) {
            size_t end = processedLine.find("*", pos + 1);
            if (end != std::string::npos) {
                std::string text = processedLine.substr(pos + 1, end - pos - 1);
                processedLine.replace(pos, end - pos, "<em>" + text + "</em>");
                pos += 9; // length of "<em>text</em>"
            } else {
                break;
            }
        }

        // Handle lists
        if (processedLine.substr(0, 1) == "-") {
            if (!inList) {
                html += "<ul>\n";
                inList = true;
            }
            html += "  <li>" + processedLine.substr(1) + "</li>\n";
        } else if (processedLine.substr(0, 1) == "1.") {
            if (!inList) {
                html += "<ol>\n";
                inList = true;
            }
            html += "  <li>" + processedLine.substr(2) + "</li>\n";
        } else {
            if (inList) {
                html += "</ul>\n";
                inList = false;
            }
            html += "<p>" + processedLine + "</p>\n";
        }
    }

    // Close any open list
    if (inList) {
        html += "</ul>\n";
    }

    return html;
}
```

---

### 📌 Example Usage

```cpp
#include <iostream>

int main() {
    std::string markdown = 
        "# Header\n\n"
        "**Bold** and *italic* text.\n\n"
        "- Item 1\n"
        "- Item 2\n\n"
        "1. First item\n"
        "2. Second item";

    std::string html = markdownToHtml(markdown);
    std::cout << html;
    return 0;
}
```

---

### 📌 Output

```html
<h1>Header</h1>
<strong>Bold</strong> and <em>italic</em> text.
<ul>
  <li>Item 1</li>
  <li>Item 2</li>
</ul>
<ol>
  <li>First item</li>
  <li>Second item</li>
</ol>
```

---

### 📌 Notes

- This is a **very basic** Markdown parser and does **not** support all Markdown syntax (e.g., links, images, code blocks, tables, etc.).
- For a more robust solution, consider using a well-maintained Markdown library like [markdown-cpp](https://github.com/jbeder/markdown) or [pandoc](https://pandoc.org/).

